const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

let sharp;
try {
  sharp = require('sharp');
} catch(e) {
  throw new Error(
    '[Generate Movie] sharp module not available. ' +
    'Ensure NODE_FUNCTION_ALLOW_EXTERNAL=* is set when starting n8n. ' +
    'Error: ' + e.message
  );
}

// ── Parameters ──────────────────────────────────────────────────
const params = $('Set Global Parameters').first().json;
const testCardFilter = (params.TestCardFilter || '').trim();
const HOLD  = parseInt(params.HoldFrames)  || 2;
const BLEND = parseInt(params.BlendFrames) || 4;
const FPS   = parseInt(params.FPS)         || 12;
const SIZE  = 512;

const raw = $input.first().json;
const deck = raw.data !== undefined ? raw.data : raw;

const deckDir = ((deck.Assets && deck.Assets.Directory)
  ? deck.Assets.Directory
  : 'D:/data/cards/Standard').replace(/\//g, path.sep);

const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error('[Generate Movie] No Cards found in Deck.json.');
}

// ── Helpers ─────────────────────────────────────────────────────
async function loadFrame(imagePath) {
  return sharp(imagePath)
    .resize(SIZE, SIZE, { fit: 'cover', position: 'centre' })
    .removeAlpha()
    .raw()
    .toBuffer();
}

function blendBuffers(a, b, t) {
  const out = Buffer.alloc(a.length);
  for (let i = 0; i < a.length; i++) {
    out[i] = Math.round(a[i] * (1 - t) + b[i] * t);
  }
  return out;
}

async function writeFrame(buf, outPath) {
  await sharp(buf, { raw: { width: SIZE, height: SIZE, channels: 3 } })
    .png()
    .toFile(outPath);
}

// ── Filter cards ────────────────────────────────────────────────
const filteredCards = testCardFilter
  ? cardRefs.filter(c => c.Card === testCardFilter)
  : cardRefs;

if (filteredCards.length === 0) {
  throw new Error(
    '[Generate Movie] No cards matched filter: ' +
    JSON.stringify(testCardFilter) +
    '. Check that TestCardFilter matches a Card name in Deck.json.'
  );
}

const results = { processed: 0, skipped: 0, failed: 0, cards: [] };

for (const cardRef of filteredCards) {
  const cardName = cardRef.Card;
  const cardFilePath = path.join(
    deckDir,
    cardRef.File.replace(/\//g, path.sep)
  );

  let cardRaw;
  try {
    cardRaw = JSON.parse(
      fs.readFileSync(cardFilePath, 'utf8').replace(/^\uFEFF/, '')
    );
  } catch (e) {
    console.warn('[Generate Movie] Cannot read card: ' + cardName + ': ' + e.message);
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'Cannot read: ' + e.message });
    continue;
  }

  const card = cardRaw['data.Cards'] || cardRaw;
  const cardDir = (card.Directory || path.join(deckDir, 'Cards'))
    .replace(/\//g, path.sep);

  const uprightImageName = card.Assets && card.Assets.UprightImage;
  if (!uprightImageName) { results.skipped++; results.cards.push({ card: cardName, status: 'skipped', reason: 'No Assets.UprightImage' }); continue; }

  const uprightRecord = (card.records || []).find(r => r.Orientation === 'upright');
  if (!uprightRecord) { results.skipped++; results.cards.push({ card: cardName, status: 'skipped', reason: 'No upright record' }); continue; }

  const movieName = uprightRecord.Assets && uprightRecord.Assets.Movie;
  if (!movieName) { results.skipped++; results.cards.push({ card: cardName, status: 'skipped', reason: 'No Movie field' }); continue; }

  const cardImageName = uprightRecord.Assets && uprightRecord.Assets.CardImage;
  if (!cardImageName) { results.skipped++; results.cards.push({ card: cardName, status: 'skipped', reason: 'No CardImage field' }); continue; }

  const movieOutputPath = path.join(cardDir, movieName);
  if (fs.existsSync(movieOutputPath)) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'Movie already exists' });
    continue;
  }

  // ── Build source frame paths ────────────────────────────────
  const slug = cardName.replace(/[()]/g, '').replace(/\s+/g, '_');
  const sourcePaths = [];
  let missingFrame = false;

  // 1. UprightImage
  const uprightPath = path.join(cardDir, uprightImageName);
  if (!fs.existsSync(uprightPath)) { results.skipped++; results.cards.push({ card: cardName, status: 'skipped', reason: 'UprightImage not found' }); continue; }
  sourcePaths.push(uprightPath);

  // 2. FOCUST_UPRIGHT_XXX_00 through _05
  for (let i = 0; i <= 5; i++) {
    const name = 'FOCUST_UPRIGHT_' + slug + '_' + String(i).padStart(2, '0') + '.png';
    const p = path.join(cardDir, name);
    if (!fs.existsSync(p)) { results.skipped++; results.cards.push({ card: cardName, status: 'skipped', reason: 'Missing: ' + name }); missingFrame = true; break; }
    sourcePaths.push(p);
  }
  if (missingFrame) continue;

  // 3. CardImage
  const cardImagePath = path.join(cardDir, cardImageName);
  if (!fs.existsSync(cardImagePath)) { results.skipped++; results.cards.push({ card: cardName, status: 'skipped', reason: 'CardImage not found' }); continue; }
  sourcePaths.push(cardImagePath);

  // 4. FOCUS_UPRIGHT_XXX_07 through _14
  for (let i = 7; i <= 14; i++) {
    const name = 'FOCUS_UPRIGHT_' + slug + '_' + String(i).padStart(2, '0') + '.png';
    const p = path.join(cardDir, name);
    if (!fs.existsSync(p)) { results.skipped++; results.cards.push({ card: cardName, status: 'skipped', reason: 'Missing: ' + name }); missingFrame = true; break; }
    sourcePaths.push(p);
  }
  if (missingFrame) continue;

  // ── Load, blend, and encode ─────────────────────────────────
  const tmpDir = path.join(cardDir, '_movie_tmp_' + slug);
  fs.mkdirSync(tmpDir, { recursive: true });

  let frameNum = 0;
  try {
    const sourceBuffers = await Promise.all(sourcePaths.map(p => loadFrame(p)));

    for (let s = 0; s < sourceBuffers.length; s++) {
      // Hold current keyframe
      for (let h = 0; h < HOLD; h++) {
        await writeFrame(sourceBuffers[s], path.join(tmpDir, String(frameNum).padStart(4, '0') + '.png'));
        frameNum++;
      }
      // Crossfade to next keyframe
      if (s < sourceBuffers.length - 1) {
        for (let b = 1; b <= BLEND; b++) {
          const t = b / (BLEND + 1);
          const blended = blendBuffers(sourceBuffers[s], sourceBuffers[s + 1], t);
          await writeFrame(blended, path.join(tmpDir, String(frameNum).padStart(4, '0') + '.png'));
          frameNum++;
        }
      }
    }
  } catch (e) {
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'blend: ' + e.message });
    fs.rmSync(tmpDir, { recursive: true, force: true });
    continue;
  }

  // Encode with ffmpeg
  const inputPattern = path.join(tmpDir, '%04d.png').replace(/\\/g, '/');
  const outputFwd = movieOutputPath.replace(/\\/g, '/');

  try {
    execSync(
      'ffmpeg -y -framerate ' + FPS +
      ' -i "' + inputPattern + '"' +
      ' -c:v mpeg2video -q:v 2 -pix_fmt yuv420p' +
      ' "' + outputFwd + '"',
      { encoding: 'utf8', timeout: 120000 }
    );
  } catch (e) {
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'ffmpeg: ' + (e.stderr || e.message) });
    fs.rmSync(tmpDir, { recursive: true, force: true });
    continue;
  }

  fs.rmSync(tmpDir, { recursive: true, force: true });

  const duration = (frameNum / FPS).toFixed(1);
  results.processed++;
  results.cards.push({
    card: cardName,
    status: 'generated',
    movie: movieOutputPath,
    outputFrames: frameNum,
    duration: duration + 's'
  });
}

if (results.processed === 0 && results.failed === 0 && results.skipped === 0) {
  throw new Error(
    '[Generate Movie] No cards processed. ' +
    'Check TestCardFilter and Deck.json Cards array.'
  );
}

return [{ json: results }];
